customCSS:
/* Midnight Aurora - Northern Lights */
@import url('https://fonts.googleapis.com/css2?family=Exo+2:wght@300;400;600;700&family=Nunito:wght@300;400;600&family=Fira+Code&display=swap');

.cyber-glow {
  background: 
    radial-gradient(ellipse 800px 200px at 20% 0%, rgba(64, 232, 112, 0.12), transparent),
    radial-gradient(ellipse 600px 300px at 50% 5%, rgba(168, 110, 255, 0.1), transparent),
    radial-gradient(ellipse 700px 200px at 80% 0%, rgba(64, 216, 160, 0.08), transparent);
  animation: auroraShift 15s ease-in-out infinite;
}

@keyframes auroraShift {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.7; }
}

.stat-card {
  border: 1px solid rgba(64, 216, 160, 0.12);
  backdrop-filter: blur(10px);
  background: rgba(18, 24, 34, 0.85);
}

.stat-card::before {
  background: linear-gradient(90deg, #40e870, #40d8a0, #a86eff);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(64, 216, 160, 0.3);
  box-shadow: 0 4px 30px rgba(64, 216, 160, 0.12);
}

.stat-value {
  text-shadow: 0 0 18px currentColor;
}

.celebration-title {
  background: linear-gradient(135deg, #40e870, #40d8a0, #a86eff);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(64, 216, 160, 0.08);
  background: rgba(18, 24, 34, 0.7);
}

.miner-card:hover {
  border-color: rgba(168, 110, 255, 0.2);
}
